const body = $input.first().json.body || $input.first().json;
const own_profile_id = body.own_profile_id;
const user_id = body.user_id;

if (!own_profile_id) throw new Error('Missing required field: own_profile_id');
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(own_profile_id)) {
  throw new Error('own_profile_id must be a valid UUID');
}
if (!user_id) throw new Error('Missing required field: user_id');
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(user_id)) {
  throw new Error('user_id must be a valid UUID');
}

return [{ json: { own_profile_id, user_id } }];

// Merge own posts and competitor list, validate we have enough, build competitor IDs for next query
// Fetch Own Posts and Fetch Competitors are parallel branches from Validate Input — both will have executed by now.
let ownItems = [];
let compItems = [];
try { ownItems = $('Fetch Own Posts').all(); } catch (e) { ownItems = []; }
try { compItems = $('Fetch Competitors').all(); } catch (e) { compItems = []; }

// HTTP node may return either one item whose json is an array, or N items each a row.
function flatten(items) {
  if (!items || items.length === 0) return [];
  if (items.length === 1 && Array.isArray(items[0].json)) return items[0].json;
  return items.map(i => i.json);
}

const own_posts = flatten(ownItems);
const competitors = flatten(compItems);

const own_profile_id = $('Validate Input').first().json.own_profile_id;

if (own_posts.length === 0) {
  throw new Error(`No posts found for own_profile_id ${own_profile_id}. Scrape your own profile first.`);
}
if (competitors.length < 2) {
  throw new Error(`Need at least 2 competitor profiles. Found: ${competitors.length}. Add and scrape competitors first.`);
}

const competitor_ids = competitors.map(c => c.id);

return [{ json: { own_profile_id, own_posts, competitors, competitor_ids } }];

function sanitize(str) {
  if (!str) return '';
  return str.replace(/[\uD800-\uDFFF]/g, '').replace(/[\x00-\x1F\x7F]/g, ' ').trim();
}

function median(nums) {
  const s = nums.filter(n => Number.isFinite(n)).slice().sort((a, b) => a - b);
  if (s.length === 0) return 0;
  const mid = Math.floor(s.length / 2);
  return s.length % 2 ? s[mid] : (s[mid - 1] + s[mid]) / 2;
}

// Tag a post with how far it stands out from its own creator's median.
// Median (not mean) so a single viral hit doesn't pull its own baseline up
// and self-suppress the signal.
function tagOutliers(posts, label) {
  if (!posts || posts.length === 0) return [];
  const med = Math.max(median(posts.map(p => p.likes || 0)), 1);
  return posts.map(p => Object.assign({}, p, {
    profile_label: label,
    profile_median_likes: med,
    outlier_ratio: (p.likes || 0) / med,
  }));
}

function formatPostsTagged(posts, limit) {
  if (!posts || posts.length === 0) return '  (no posts scraped yet)';
  return posts.slice(0, limit).map((p, i) => {
    const caption = sanitize(p.caption || '').slice(0, 100);
    const date = (p.posted_at || '').slice(0, 10);
    const ratio = p.outlier_ratio ? ' (' + p.outlier_ratio.toFixed(1) + 'x median)' : '';
    return '  ' + String(i+1).padStart(2) + '. [' + (p.content_type||'unknown').padEnd(8) + '] ' + date + ' | L:' + (p.likes||0) + ' C:' + (p.comments||0) + ' V:' + (p.views||0) + ratio + ' | "' + caption + '"';
  }).join('\n');
}

function formatOutlierLine(p, i) {
  const caption = sanitize(p.caption || '').slice(0, 140);
  const date = (p.posted_at || '').slice(0, 10);
  return '  ' + String(i+1).padStart(2) + '. ' + p.profile_label + ' [' + (p.content_type||'unknown') + '] ' + date + ' | L:' + (p.likes||0) + ' (' + p.outlier_ratio.toFixed(1) + 'x ' + p.profile_label + ' median ' + Math.round(p.profile_median_likes) + ') C:' + (p.comments||0) + ' V:' + (p.views||0) + ' | "' + caption + '"';
}

const upstream = $('Merge Profiles').first().json;
const validate = $('Validate Input').first().json;
const { own_profile_id, own_posts, competitors } = upstream;
const own_username = (validate.own_username || '').toLowerCase();
const ownHandleLabel = own_username ? '@' + own_username : 'own_account';

const allPostsRaw = $input.first().json;
const allPosts = Array.isArray(allPostsRaw) ? allPostsRaw : [allPostsRaw];

// Group competitor posts by profile_id, then tag each group with outlier
// ratios against its own median.
const postsByProfile = {};
for (const post of allPosts) {
  if (!postsByProfile[post.profile_id]) postsByProfile[post.profile_id] = [];
  postsByProfile[post.profile_id].push(post);
}

const taggedByProfile = {};
for (const comp of competitors) {
  taggedByProfile[comp.id] = tagOutliers(postsByProfile[comp.id] || [], '@' + comp.username);
}
const taggedOwn = tagOutliers(own_posts, ownHandleLabel);

// Build the VIRAL OUTLIERS section: top 8 outliers across all competitors,
// ratio >= 3 minimum, sorted by ratio descending. Posts with very short
// captions (< 20 chars after sanitize) are de-prioritized — likely
// music-only montages where Claude can't infer a format from the caption.
const allCompetitorTagged = competitors.flatMap(c => taggedByProfile[c.id] || []);
const outlierCandidates = allCompetitorTagged
  .filter(p => p.outlier_ratio >= 3)
  .map(p => Object.assign({}, p, { _captionLen: sanitize(p.caption || '').length }))
  .sort((a, b) => {
    // Primary sort: ratio descending. Posts with usable captions (>=20
    // chars) get a tie-breaker bonus over caption-less ones.
    const aBonus = a._captionLen >= 20 ? 0 : 0.5;
    const bBonus = b._captionLen >= 20 ? 0 : 0.5;
    return (b.outlier_ratio - bBonus) - (a.outlier_ratio - aBonus);
  })
  .slice(0, 8);

const competitorCount = competitors.length;

const ownSection = '--- USER OWN ACCOUNT (' + ownHandleLabel + ') --- ' + own_posts.length + ' posts (median ' + Math.round(median(own_posts.map(p => p.likes || 0))) + ' likes) ---\n' + formatPostsTagged(taggedOwn, 30);

let competitorSections = '';
for (const comp of competitors) {
  const tagged = taggedByProfile[comp.id] || [];
  const med = tagged[0] ? Math.round(tagged[0].profile_median_likes) : 0;
  competitorSections += '\n--- COMPETITOR: @' + comp.username + ' (' + tagged.length + ' posts, median ' + med + ' likes) ---\n' + formatPostsTagged(tagged, 50) + '\n';
}

const outlierSection = outlierCandidates.length > 0
  ? '--- VIRAL OUTLIERS (single posts that wildly outperformed their own creator baseline) ---\n' + outlierCandidates.map((p, i) => formatOutlierLine(p, i)).join('\n')
  : '--- VIRAL OUTLIERS ---\n  (no posts >= 3x their creator median this run)';

const systemPrompt = 'You are a social media growth analyst specialising in Instagram content strategy. Analyze all provided posts and detect TWO kinds of patterns: (1) validated trends repeated across multiple creators, and (2) standout hits where a single creator wildly outperformed their own baseline. Return ONLY a valid JSON array, no markdown, no code blocks, no explanation outside the JSON. Every recommendation must be concrete enough that the creator can film it tomorrow without asking follow-up questions.';

const userPrompt = 'Analyze the following Instagram posts from ' + competitorCount + ' competitor accounts plus the user own account (' + ownHandleLabel + ').\n\n' +
'The user goal is to discover NEW content ideas inspired by competitors. Surface BOTH cross-account validated patterns AND single-creator viral standouts that the user could borrow.\n\n' +
'IDENTIFY TWO KINDS OF TRENDS:\n\n' +
'TYPE 1 — VALIDATED (trend_type = "validated"):\n' +
'A content pattern that appears in TOP-20% posts of 2 or more competitors. Calculate performance_multiplier as: avg likes of pattern posts / avg likes of all posts for that competitor (a ratio in [1.5, 25]).\n\n' +
'TYPE 2 — STANDOUT (trend_type = "standout"):\n' +
'A single-creator viral hit. Use the VIRAL OUTLIERS section below — these are posts whose like count is >=3x their own creator median. If an outlier has a clear, borrow-able format/theme, return it as a standout trend. competitor_count = 1; performance_multiplier = the outlier ratio (e.g. 12.4 if the post got 12.4x its creator median); user_doing_it should reflect whether the user own account has shown this format. Aim for 2-4 standouts per run when outliers exist.\n\n' +
ownSection + '\n\n' + competitorSections + '\n' + outlierSection + '\n\n' +
'Return a JSON ARRAY (0-10 items), sorted by performance_multiplier descending. Each item MUST have exactly this structure:\n' +
'{\n' +
'  "trend_name": "Short descriptive name like \'Episodic Series Content\' or \'Most Challenging Day Confessional\'",\n' +
'  "one_line_summary": "Max 100 characters. Action-oriented.",\n' +
'  "trend_type": "validated",\n' +
'  "competitor_count": 4,\n' +
'  "total_competitors": ' + competitorCount + ',\n' +
'  "performance_multiplier": 3.2,\n' +
'  "why_it_works": "1-2 sentences explaining the psychological/algorithmic reason this pattern drives engagement",\n' +
'  "competitor_edge": "REQUIRED - one specific concrete thing competitors do differently or better. E.g. \'Competitor X uses 15-second cuts vs your 45-second cuts.\'",\n' +
'  "example_posts": [\n' +
'    {"caption_preview": "first 80 chars of caption", "likes": 1234, "comments": 56, "competitor": "@username"}\n' +
'  ],\n' +
'  "brief": {\n' +
'    "content": "Describe the format in ONE sentence: length, shot type, pacing.",\n' +
'    "hook": "The literal opening 3 seconds, word-for-word.",\n' +
'    "caption_structure": "Multi-line template using newline characters.",\n' +
'    "best_time": "Specific day + 2-hour window.",\n' +
'    "hashtags": ["bikepacking", "adventurecycling"]\n' +
'  },\n' +
'  "user_doing_it": false\n' +
'}\n\n' +
'Critical rules - read these twice before returning:\n\n' +
'trend_type:\n' +
'- "validated" requires competitor_count >= 2.\n' +
'- "standout" requires competitor_count = 1 AND the example_post must come from the VIRAL OUTLIERS section above (or have outlier_ratio >= 3 against its own creator median).\n' +
'- Aim for a healthy mix: surface every legitimate validated trend you find, plus 2-4 standouts when outliers carry borrow-able themes. Do not invent standouts if the outlier section is empty or all the outliers are niche-personal moments not worth borrowing.\n\n' +
'performance_multiplier:\n' +
'- For "validated": ratio = (avg likes of pattern posts) / (avg likes of ALL posts for that competitor). Number between 1.5 and 25.\n' +
'- For "standout": ratio = post likes / that creator median (taken straight from the VIRAL OUTLIERS section). Number between 3 and 30.\n' +
'- Always a number, never a string.\n\n' +
'example_posts rules:\n' +
'- example_posts must NEVER include posts from the user own account (' + ownHandleLabel + ').\n' +
'- Validated trends: include posts from at least 2 different competitors.\n' +
'- Standouts: include exactly the one viral outlier post that triggered the trend.\n' +
'- Each example_post.competitor field must be the actual @username, never "own_account" or "user".\n' +
'- A given post (same competitor + same caption) MUST appear in at most ONE trend example_posts. Do not reuse posts across trends.\n' +
'- Sort example_posts by likes descending.\n\n' +
'competitor_edge rules:\n' +
'- REQUIRED for every trend.\n' +
'- Validated + user_doing_it=true: contrast what the user does vs what competitors do better.\n' +
'- Validated + user_doing_it=false: describe the standout craft choice that makes the pattern land.\n' +
'- Standout: explain WHY this single video popped — the specific structural/emotional/visual choice the user would borrow.\n\n' +
'Content rules:\n' +
'- one_line_summary max 100 chars, starts with an action verb (Film, Record, Share, etc.).\n' +
'- brief.content, brief.hook, brief.caption_structure, brief.best_time are REQUIRED strings. brief.hashtags is a REQUIRED array of 5-8 plain strings without the # prefix.\n' +
'- user_doing_it must be a boolean.\n\n' +
'Return ONLY the JSON array. Empty array [] is acceptable only if no validated trends meet the bar AND no outlier carries a borrow-able theme.';

return [{ json: { own_profile_id, own_username, system_prompt: systemPrompt, user_prompt: userPrompt, competitor_count: competitorCount, outlier_count: outlierCandidates.length } }];

const resp = $input.first().json;
const rawText = resp?.content?.[0]?.text;
if (!rawText) throw new Error('Claude returned no content. Response: ' + JSON.stringify(resp));

const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let trends;
try {
  trends = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + '\nRaw: ' + cleaned.slice(0, 500));
}

if (!Array.isArray(trends)) throw new Error('Expected JSON array from Claude, got: ' + typeof trends);

const upstream = $('Build Claude Prompt').first().json;
const own_profile_id = upstream.own_profile_id;
const own_username = (upstream.own_username || '').toLowerCase();
const total_competitors = upstream.competitor_count;

function basics(t) {
  const mult = typeof t.performance_multiplier === 'number' ? t.performance_multiplier : parseFloat(t.performance_multiplier) || 0;
  const compCount = Number.isFinite(t.competitor_count) ? Math.round(t.competitor_count) : 0;
  return { mult, compCount };
}

// Two acceptance gates, one per trend_type. Standouts have a HIGHER
// multiplier floor (>=5) because the magnitude is the validation;
// validated trends have a LOWER floor (>=1.5) because the cross-account
// repetition is the validation.
function isValidated(t) {
  const { mult, compCount } = basics(t);
  if (t.trend_type === 'standout') return false;
  if (compCount < 2) return false;
  if (mult < 1.5 || mult > 25) return false;
  return true;
}

function isStandout(t) {
  const { mult, compCount } = basics(t);
  if (t.trend_type !== 'standout') return false;
  if (compCount !== 1) return false;
  if (mult < 5 || mult > 30) return false;
  return true;
}

const accepted = trends.filter(t => isValidated(t) || isStandout(t));
const rejected = trends.length - accepted.length;
console.log('Accepted ' + accepted.length + ' of ' + trends.length + ' trends (rejected ' + rejected + ')');

// Cross-trend example dedup: a given post belongs to at most one trend.
const seenExampleKeys = new Set();
function exampleKey(ex) {
  const comp = String(ex.competitor || '').replace(/^@/, '').toLowerCase();
  const cap = String(ex.caption_preview || '').toLowerCase().replace(/\s+/g, ' ').slice(0, 40);
  return comp + '::' + cap;
}

const enriched = accepted.map(t => {
  const examples = Array.isArray(t.example_posts) ? t.example_posts : [];
  const ownScrubbed = examples.filter(ex => {
    const comp = String(ex.competitor || '').replace(/^@/, '').toLowerCase();
    const isOwn =
      comp === 'own_account' ||
      comp === 'user' ||
      (own_username && comp === own_username);
    if (isOwn) console.log('Removed own-handle example from trend "' + t.trend_name + '"');
    return !isOwn;
  });
  const deduped = ownScrubbed.filter(ex => {
    const k = exampleKey(ex);
    if (seenExampleKeys.has(k)) {
      console.log('Removed duplicate example "' + (ex.caption_preview || '').slice(0, 30) + '" from trend "' + t.trend_name + '"');
      return false;
    }
    seenExampleKeys.add(k);
    return true;
  });
  return Object.assign({}, t, { example_posts: deduped });
});

const withExamples = enriched.filter(t => Array.isArray(t.example_posts) && t.example_posts.length > 0);
console.log('After own-scrub + cross-trend dedup: ' + withExamples.length + ' of ' + accepted.length + ' trends retained');

const final = withExamples.map(t => {
  const brief = (t.brief && typeof t.brief === 'object') ? t.brief : {};
  const multiplier = typeof t.performance_multiplier === 'number' ? t.performance_multiplier : parseFloat(t.performance_multiplier) || 0;
  const competitor_count = Number.isFinite(t.competitor_count) ? Math.round(t.competitor_count) : null;
  const effective_total = Number.isFinite(t.total_competitors) ? Math.round(t.total_competitors) : total_competitors;
  const confidence = competitor_count != null && effective_total > 0
    ? competitor_count / effective_total
    : 0;
  const hashtags = Array.isArray(brief.hashtags)
    ? brief.hashtags.map(h => String(h).replace(/^#/, '').trim()).filter(Boolean)
    : null;
  // Normalize trend_type to one of the two allowed values (the schema
  // CHECK constraint will reject anything else; better to default than fail
  // the insert).
  const trend_type = t.trend_type === 'standout' ? 'standout' : 'validated';
  return {
    profile_id: own_profile_id,
    trend_name: t.trend_name || 'Unknown Trend',
    one_line_summary: typeof t.one_line_summary === 'string' ? t.one_line_summary.slice(0, 140) : null,
    trend_type,
    competitor_count,
    total_competitors: effective_total,
    confidence,
    performance_multiplier: multiplier,
    why_it_works: t.why_it_works || '',
    competitor_edge: typeof t.competitor_edge === 'string' ? t.competitor_edge.slice(0, 500) : null,
    example_posts: JSON.stringify(t.example_posts || []),
    content_format: typeof brief.content === 'string' ? brief.content : null,
    hook: typeof brief.hook === 'string' ? brief.hook : null,
    caption_structure: typeof brief.caption_structure === 'string' ? brief.caption_structure : null,
    best_time: typeof brief.best_time === 'string' ? brief.best_time : null,
    hashtags: hashtags ? JSON.stringify(hashtags) : null,
    recommendation: t.mega_tip || t.one_line_summary || '',
    suggested_schedule: typeof brief.best_time === 'string' ? brief.best_time : '',
    is_mega_tip: t.user_doing_it === false && multiplier > 2,
    user_doing_it: t.user_doing_it === true
  };
});

const validatedCount = final.filter(t => t.trend_type === 'validated').length;
const standoutCount = final.filter(t => t.trend_type === 'standout').length;
console.log('Parsed ' + final.length + ' trends — ' + validatedCount + ' validated, ' + standoutCount + ' standouts. Mega-tips: ' + final.filter(t => t.is_mega_tip).length);

if (final.length === 0) {
  return [{ json: { _empty: true, profile_id: own_profile_id, total_competitors } }];
}

return final.map(r => ({ json: r }));

// Filter out the _empty sentinel that If-Has-Trends routes around the
// Insert step. Without this, an empty-result run would be reported as
// trends_detected: 1 with a garbage row in the response.
const allUpstream = $('Parse & Enrich Response').all();
const upstream = allUpstream.filter(i => !(i.json && i.json._empty));

const megaTips = upstream.filter(i => i.json.is_mega_tip).length;
const total = upstream.length;

return [{
  json: {
    success: true,
    trends_detected: total,
    mega_tips: megaTips,
    insights: upstream.map(i => ({
      trend_name: i.json.trend_name,
      confidence_label: i.json.confidence_label,
      performance_multiplier: i.json.performance_multiplier,
      is_mega_tip: i.json.is_mega_tip,
      user_doing_it: i.json.user_doing_it
    }))
  }
}];
